CREATE TABLE IF NOT EXISTS `notificacoes_atendimento` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `numatend` varchar(100) NOT NULL,
  `estabelecimentoId` int,
  `observacao` text NOT NULL DEFAULT '',
  `usuario` varchar(255),
  `criadoEm` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS `idx_notif_atend_numatend` ON `notificacoes_atendimento` (`numatend`);
CREATE INDEX IF NOT EXISTS `idx_notif_atend_estab` ON `notificacoes_atendimento` (`estabelecimentoId`);
CREATE INDEX IF NOT EXISTS `idx_notif_atend_criado` ON `notificacoes_atendimento` (`criadoEm`);

CREATE TABLE IF NOT EXISTS `notificacoes_atendimento_item` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `notificacaoId` int NOT NULL,
  `motivo` varchar(255) NOT NULL,
  `setor` varchar(255) NOT NULL DEFAULT '',
  `medico` varchar(255) NOT NULL DEFAULT '',
  `criadoEm` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS `idx_notif_item_notificacao` ON `notificacoes_atendimento_item` (`notificacaoId`);
CREATE INDEX IF NOT EXISTS `idx_notif_item_motivo` ON `notificacoes_atendimento_item` (`motivo`);

